INSERT INTO public.problems VALUES (208, '链表的奇偶重排', '链表的奇偶重排', '牛客', 'Medium', 'linked-list', '给定一个单链表，请设定一个函数，将链表的奇数位节点和偶数位节点分别放在一起，重排后输出。

注意是节点的编号而非节点的数值。

数据范围：节点数量满足 $0 \le n \le 10^5$，节点中的值都满足 $0 \le val \le 1000$

要求：空间复杂度 $O(n)$，时间复杂度 $O(n)$

难度提示：中等

## 样例

### 样例 1

**输入：**
```
{1,2,3,4,5,6}
```

**输出：**
```
{1,3,5,2,4,6}
```

**说明：**
1->2->3->4->5->6->NULL重排后为1->3->5->2->4->6->NULL

### 样例 2

**输入：**
```
{1,4,6,3,7}
```

**输出：**
```
{1,6,7,4,3}
```

**说明：**
1->4->6->3->7->NULL重排后为1->6->7->4->3->NULL奇数位节点有1,6,7，偶数位节点有4,3。重排后为1,6,7,4,3', '', '["\u672a\u5206\u7c7b"]', '[]', '["Python", "C++", "Java"]', '{"Python": "def solve() -> None:\n    pass", "C++": "#include <bits/stdc++.h>\nusing namespace std;\n\nint main() {\n    return 0;\n}", "Java": "public class Main {\n    public static void main(String[] args) {\n    }\n}"}', '牛客', '牛客', '中', 2026, 'https://www.nowcoder.com/practice/02bf49ea45cd486daa031614f9bd6fc3?tpId=295&tqId=1073463&sourceUrl=%2Fexam%2Foj%3FquestionJobId%3D10%26subTabName%3Donline_coding_page', 'https://www.nowcoder.com/practice/02bf49ea45cd486daa031614f9bd6fc3?tpId=295&tqId=1073463&sourceUrl=%2Fexam%2Foj%3FquestionJobId%3D10%26subTabName%3Donline_coding_page', '未开始', '2026-07-03T11:30:32.667483+00:00', '2026-07-03T12:11:04.792531+00:00', 2000, 262144, '常见101', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.problems VALUES (121, '山峰间的极限跳跃', '山峰间的极限跳跃', '华为', 'Medium', 'tree', '您是一位极限运动家，正挑战一片由计算机生成的、结构奇特的数字山脉。

这片山脉由 $N$ 个山峰组成，每个山峰都有其独特的海拔高度。

您的目标是规划出一条最长的、符合“极限跳跃”规则的下山路径。

这片数字山脉的结构可以用一棵二叉树来精确描述。您规划的路径必须遵循一系列严格的规则，我们称之为一条“极限交替路径”：

路径方向 : 路线必须严格自上而下，即只能从一个山峰移动到与之直接相连的子山峰。

严格交替 : 路径上海拔的变化必须是严格的交替上升和下降。例如，一条合法的路径可以是海拔 $p_1 \to p_2 \to p_3 \to p_4$，其海拔序列满足 $p_1 < p_2 > p_3 < p_4$。无论是“先升后降”还是“先降后升”的交替模式都是允许的。

极限跳跃 : 每次移动（从一个山峰到下一个）的海拔绝对差值必须大于或等于一个给定的阈值 $k$。形式化地，对于路径上任意相邻的两个山峰 $A$ 和 $B$，必须满足 $|\text{altitude}(B) - \text{altitude}(A)| \ge k$。

您的任务是找出在这片山脉中，能够规划出的最长“极限交替路径”的长度。路径的长度以其所包含的山峰数量计算。

## 输入格式

第一行包含两个整数 $N$ 和 $K$。
$N$ 是山峰的总数, $1 \le N \le 10000$。
$K$ 是要求的最小海拔差 (极限跳跃阈值), $1 \le K \le 100$。
接下来的 $N$ 行描述了山脉的结构。每行包含三个整数 $X, Y, Z$：
$X$ 是当前山峰的海拔。
$Y$ 是其左侧子山峰的海拔。
$Z$ 是其右侧子山峰的海拔。
如果某个子山峰不存在，则用 $-1$ 表示。
所有山峰的海拔高度都在 $[1, 100000]$ 范围内，且保证互不相同。
这 $N$ 行的输入顺序遵循该山脉地图的先序遍历顺序。

## 输出格式

一个整数，代表最长“极限交替路径”的长度。

## 样例

### 样例 1

**输入：**
```
6 10
20 10 -1
10 21 -1
21 -1 11
11 -1 22
22 12 -1
12 -1 -1
```

**输出：**
```
6
```', '', '["\u672a\u5206\u7c7b"]', '[]', '["Python", "C++", "Java"]', '{"Python": "def solve() -> None:\n    pass", "C++": "#include <bits/stdc++.h>\nusing namespace std;\n\nint main() {\n    return 0;\n}", "Java": "public class Main {\n    public static void main(String[] args) {\n    }\n}"}', '牛客', '牛客', '中', 2025, 'https://www.nowcoder.com/exam/test/97686405/detail?pid=64952987&examPageSource=Company&subTabName=written_page&testCallback=https%3A%2F%2Fwww.nowcoder.com%2Fexam%2Fcompany%3FcurrentTab%3Drecommand%26jobId%3D100%26tagIds%3D239&testclass=%E8%BD%AF%E4%BB%B6%E5%BC%80%E5%8F%91', 'https://www.nowcoder.com/exam/test/97686405/detail?pid=64952987&examPageSource=Company&subTabName=written_page&testCallback=https%3A%2F%2Fwww.nowcoder.com%2Fexam%2Fcompany%3FcurrentTab%3Drecommand%26jobId%3D100%26tagIds%3D239&testclass=%E8%BD%AF%E4%BB%B6%E5%BC%80%E5%8F%91', '未开始', '2026-07-02T15:16:39.246549+00:00', '2026-07-02T15:22:46.118808+00:00', 2000, 262144, '开发', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.problems VALUES (120, '中世纪的商路', '中世纪的商路', '华为', 'Medium', 'graphs', '时值中世纪，您是一位雄心勃勃的商人，计划在地中海的各大城市之间开展一系列贸易活动。您获得了一份航海图，上面标注了 $n$ 条利润丰厚的贸易航线。每一条航线都连接着两个港口，有明确的出发和到达日期，并需要一支特定规模的商队来完成。您的目标是在有限的资源下，规划出最赚钱的贸易路线。

您有 $n$ 个贸易机会可供选择。对于第 $i$ 个贸易机会，您掌握以下信息：

出发时间 : $startTime_i$

到达时间 : $endTime_i$

所需商队规模 : $effort_i$

预期利润 : $profit_i$

您所能召集的最大商队规模为 $maxEffort$。在任何时候，您都只能派遣一支商队，因此您不能同时进行时间上重叠的贸易活动。然而，如果一趟贸易在时间 $X$ 结束，您可以立即开始一趟新的、在时间 $X$ 出发的贸易。

您的任务是制定一份贸易计划，选择一部分贸易机会来执行，使得总利润最大化，同时确保任何时刻派遣的商队规模之和都不超过您的最大能力 $maxEffort$。

## 输入格式

输入包含 5 个参数，前四个是描述贸易机会的数组，第五个是您的最大商队规模。

1. 出发时间数组 ($startTime$) : 一个整数数组，表示每个贸易机会的出发时间。
2. 到达时间数组 ($endTime$) : 一个整数数组，表示每个贸易机会的到达时间。
3. 商队规模数组 ($effort$) : 一个整数数组，表示完成每个贸易机会所需的商队规模。
4. 利润数组 ($profit$) : 一个整数数组，表示完成每个贸易机会可获得的利润。
5. 最大商队规模 ($maxEffort$) : 一个整数，表示您能召集的最大商队规模。

约束条件 :
所有数组的长度 $n$ 相等，且 $1 \le n \le 2000$。
$1 \le startTime_i < endTime_i \le 2000$。
$1 \le effort_i, profit_i \le 10^9$。
$1 \le maxEffort \le 1000$。

输入格式 :
输入共 5 行，每行代表一个参数。前 4 行的数组数据由空格分隔。

## 输出格式

一个整数，代表您能获得的最大总利润。

## 样例

### 样例 1

**输入：**
```
2 4 7
6 8 11
20 20 20
30 90 30
40
```

**输出：**
```
90
```', '', '["\u672a\u5206\u7c7b"]', '[]', '["Python", "C++", "Java"]', '{"Python": "def solve() -> None:\n    pass", "C++": "#include <bits/stdc++.h>\nusing namespace std;\n\nint main() {\n    return 0;\n}", "Java": "public class Main {\n    public static void main(String[] args) {\n    }\n}"}', '牛客', '牛客', '中', 2025, 'https://www.nowcoder.com/exam/test/97686489/detail?pid=64933347&examPageSource=Company&subTabName=written_page&testCallback=https%3A%2F%2Fwww.nowcoder.com%2Fexam%2Fcompany%3FquestionJobId%3D10%26subTabName%3Dwritten_page&testclass=%E8%BD%AF%E4%BB%B6%E5%BC%80%E5%8F%91', 'https://www.nowcoder.com/exam/test/97686489/detail?pid=64933347&examPageSource=Company&subTabName=written_page&testCallback=https%3A%2F%2Fwww.nowcoder.com%2Fexam%2Fcompany%3FquestionJobId%3D10%26subTabName%3Dwritten_page&testclass=%E8%BD%AF%E4%BB%B6%E5%BC%80%E5%8F%91', '未开始', '2026-07-02T15:16:39.188716+00:00', '2026-07-02T15:22:58.594225+00:00', 2000, 262144, '开发', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.problems VALUES (119, '星际勘探者', '星际勘探者', '华为', 'Medium', 'simulation', '公元 2242 年，您是星际勘探舰“奥德赛号”的舰长，正在执行一项穿越未知小行星带的危险任务。

远程扫描显示，前方有一条由 $m$ 颗小行星组成的直线路径，每一颗都蕴藏着宝贵的能量水晶。

您的任务是规划航线，最大限度地补充舰船的能量储备。

您将要穿越的星系包含 $m$ 颗小行星，编号从 $1$ 到 $m$。您的舰船只能沿着编号递增的方向前进，无法后退。

初始状态 : 您的舰船携带有 $n$ 个单位的初始能量。

航行消耗 : 从当前位置航行到下一颗小行星，需要消耗 $1$ 个单位的能量。如果能量为 $0$，舰船将无法启动，无法航行到新的小行星。

能量采集 : 您装备了一台高能水晶采集器，但由于能源核心的限制，在整个任务中最多只能使用 $k$ 次。每颗小行星最多只能被采集一次。采集小行星 $i$ 上的水晶，可以为舰船瞬间补充 $a_i$ 个单位的能量。

您的目标是，在整个勘探任务的任意时刻，舰船所能达到的**最大能量值**是多少？

请注意，您可以选择不登陆任何小行星。

## 输入格式

第一行包含三个正整数 $m, n, k$ ($1 \le m, n, k \le 20$)，由空格隔开。
第二行包含 $m$ 个整数 $a_1, a_2, \dots, a_m$ ($0 \le a_i \le 20$)，代表每颗小行星上蕴含的能量水晶数量，由空格隔开。

## 输出格式

一个整数，表示在整个任务过程中，舰船能达到的最大能量值。

## 样例

### 样例 1

**输入：**
```
17 20 19
19 0 2 6 20 3 4 1 8 3 8 7 14 8 19 11 17
```

**输出：**
```
153
```', '', '["\u672a\u5206\u7c7b"]', '[]', '["Python", "C++", "Java"]', '{"Python": "def solve() -> None:\n    pass", "C++": "#include <bits/stdc++.h>\nusing namespace std;\n\nint main() {\n    return 0;\n}", "Java": "public class Main {\n    public static void main(String[] args) {\n    }\n}"}', '牛客', '牛客', '中', 2025, 'https://www.nowcoder.com/exam/test/97686489/detail?pid=64933347&examPageSource=Company&subTabName=written_page&testCallback=https%3A%2F%2Fwww.nowcoder.com%2Fexam%2Fcompany%3FquestionJobId%3D10%26subTabName%3Dwritten_page&testclass=%E8%BD%AF%E4%BB%B6%E5%BC%80%E5%8F%91', 'https://www.nowcoder.com/exam/test/97686489/detail?pid=64933347&examPageSource=Company&subTabName=written_page&testCallback=https%3A%2F%2Fwww.nowcoder.com%2Fexam%2Fcompany%3FquestionJobId%3D10%26subTabName%3Dwritten_page&testclass=%E8%BD%AF%E4%BB%B6%E5%BC%80%E5%8F%91', '未开始', '2026-07-02T15:16:39.133153+00:00', '2026-07-02T15:23:12.094008+00:00', 2000, 262144, '开发', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.problems VALUES (118, '命令行软件', '命令行软件', '华为', 'Medium', 'hashing', '在2077年，您是一位顶尖的“深空网络”工程师，负责维护一个位于遥远星系的分布式文件系统。

该系统的稳定运行对于星际通信至关重要。

现在，您需要编写一个模拟程序来测试和验证该文件系统的核心命令行功能。

## 输入格式

这个星际文件系统是一个典型的树状结构。系统的根目录表示为 $\Large /$。系统初始化时，根目录下已经创建了一个名为 usr 的用户目录，而您的初始工作目录也正是 /usr。

您需要处理一连串的命令行指令。支持的指令集如下：

mkdir: 在当前目录下，创建一个名为的新目录。如果同名目录已存在，则此指令将被忽略。
cd .. : 切换到上一级父目录。
cd: 切换到当前目录下的子目录。
ls : 列出当前目录下所有子目录的名称，并按字典序升序排列。

您将接收到 $m$ 条指令。您的任务是模拟这些指令的执行，并输出所有 ls 指令的结果。

## 输出格式

对于每一条 ls 指令，您需要输出其执行结果。每条 ls 的结果占一行，目录名之间用单个空格分隔。
特别地，如果当前目录下没有任何子目录， ls 指令应当输出一个单独的空格。

## 样例

### 样例 1

**输入：**
```
20
mkdir syadhzdgck
mkdir irky
cd ..
cd usr
ls
cd ..
ls
mkdir wfanr
cd usr
ls
cd ..
ls
mkdir fuuszuicsn
cd wfanr
cd ..
cd fuuszuicsn
cd ..
mkdir ebw
cd ebw
ls
```

**输出：**
```
irky syadhzdgck
usr
irky syadhzdgck
usr wfanr
```', '', '["\u672a\u5206\u7c7b"]', '[]', '["Python", "C++", "Java"]', '{"Python": "def solve() -> None:\n    pass", "C++": "#include <bits/stdc++.h>\nusing namespace std;\n\nint main() {\n    return 0;\n}", "Java": "public class Main {\n    public static void main(String[] args) {\n    }\n}"}', '牛客', '牛客', '中', 2025, 'https://www.nowcoder.com/exam/test/97686489/detail?pid=64933347&examPageSource=Company&subTabName=written_page&testCallback=https%3A%2F%2Fwww.nowcoder.com%2Fexam%2Fcompany%3FquestionJobId%3D10%26subTabName%3Dwritten_page&testclass=%E8%BD%AF%E4%BB%B6%E5%BC%80%E5%8F%91', 'https://www.nowcoder.com/exam/test/97686489/detail?pid=64933347&examPageSource=Company&subTabName=written_page&testCallback=https%3A%2F%2Fwww.nowcoder.com%2Fexam%2Fcompany%3FquestionJobId%3D10%26subTabName%3Dwritten_page&testclass=%E8%BD%AF%E4%BB%B6%E5%BC%80%E5%8F%91', '未开始', '2026-07-02T15:16:39.081426+00:00', '2026-07-02T15:23:25.313425+00:00', 2000, 262144, '开发', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.problems VALUES (117, '基因调控网络', '基因调控网络', '华为', 'Easy', 'graphs', '在基因组学研究中，基因之间的调控关系可以被抽象成一个有向图，我们称之为基因调控网络。

在这个网络中，每个节点代表一个基因，一条从基因 $u$ 指向基因 $v$ 的有向边表示基因 $u$ 会激活基因 $v$。

科学家们对一种被称为“协同调控模体”（Co-regulatory Motif）的特殊结构非常感兴趣。

一个协同调控模体由四个不同的基因 $a, b, c, d$ 组成，它们需要满足以下激活关系：

1. 主调节基因 $a$ 能够直接激活两个中间基因 $b$ 和 $d$。

2. 这两个中间基因 $b$ 和 $d$ 又都能直接激活同一个目标基因 $c$。

简单来说，这个结构意味着存在两条从基因 $a$ 到基因 $c$ 的长度为 2 的不同路径，一条路径为 $a \rightarrow b \rightarrow c$，另一条为 $a \rightarrow d \rightarrow c$。

给定一个基因调控网络的结构，请计算该网络中总共存在多少个这样的“协同调控模体”。

## 输入格式

第一行包含两个整数 $n$ 和 $m$，使用空格隔开。
$n$ 代表基因的数量（编号从 $1$ 到 $n$），$m$ 代表已知的直接激活关系的数量。
接下来的 $m$ 行，每行包含两个整数 $u, v$，表示存在一条从基因 $u$ 到基因 $v$ 的激活关系。

数据范围：$1 \le n \le 1000$，$0 \le m \le 10000$。

## 输出格式

输出一个整数，代表网络中“协同调控模体”的总数量。

## 样例

### 样例 1

**输入：**
```
24 60
1 4
1 6
1 7
2 9
2 12
2 13
2 16
2 19
2 23
3 5
4 3
4 6
4 11
4 15
4 17
