INSERT INTO public.problems VALUES (575, '最小旋转次数', '最小旋转次数', '蚂蚁', 'Easy', 'string', '薯条哥认为 $Z、 N$ 字符可以通过一次 $90°$ 的顺时针或者逆时针旋转相互得到。
现在薯条哥给定一个长度为 $n$，仅由字符$N$和$Z$，构成的字符串,请你帮助薯条哥计算至少需要旋转多少次才可以使得字符串变得只包含一个字母类型。
