```
""
```

**输出：**
```
[""]
```', '', '["\u672a\u5206\u7c7b"]', '[]', '["Python", "C++", "Java"]', '{"Python": "def solve() -> None:\n    pass", "C++": "#include <bits/stdc++.h>\nusing namespace std;\n\nint main() {\n    return 0;\n}", "Java": "public class Main {\n    public static void main(String[] args) {\n    }\n}"}', '牛客', '牛客', '中', 2026, 'https://www.nowcoder.com/practice/fe6b651b66ae47d7acce78ffdd9a96c7?tpId=295&tqId=23291&sourceUrl=%2Fexam%2Foj%3FquestionJobId%3D10%26subTabName%3Donline_coding_page', 'https://www.nowcoder.com/practice/fe6b651b66ae47d7acce78ffdd9a96c7?tpId=295&tqId=23291&sourceUrl=%2Fexam%2Foj%3FquestionJobId%3D10%26subTabName%3Donline_coding_page', '未开始', '2026-07-03T17:38:55.362448+00:00', '2026-07-03T17:43:15.437166+00:00', 2000, 262144, '常见101', NULL, NULL) ON CONFLICT DO NOTHING;
