INSERT INTO public.problems VALUES (265, '连续子数组的最大和', '连续子数组的最大和', '牛客', 'Easy', 'dynamic-programming', '输入一个长度为n的整型数组array，数组中的一个或连续多个整数组成一个子数组，子数组最小长度为1。求所有子数组的和的最大值。 
