INSERT INTO public.problems VALUES (273, '买卖股票的最好时机(一)', '买卖股票的最好时机(一)', '牛客', 'Easy', 'dynamic-programming', '假设你有一个数组prices，长度为n，其中prices[i]是股票在第i天的价格，请根据这个价格数组，返回买卖股票能获得的最大收益 
1.你可以买入一次股票和卖出一次股票，并非每天都可以买入或卖出一次，总共只能买入和卖出一次，且买入必须在卖出的前面的某一天 
2.如果不能获取到任何利润，请返回0 
3.假设买入卖出均无手续费

数据范围： $0 \le n \le 10^5 , 0 \le val \le 10^4$

要求：空间复杂度 $O(1)$，时间复杂度 $O(n)$

难度提示：简单

## 样例

### 样例 1

**输入：**
```
[8,9,2,5,4,7,1]
```

**输出：**
```
5
```

**说明：**
在第3天(股票价格 = 2)的时候买入，在第6天(股票价格 = 7)的时候卖出，最大利润 = 7-2 = 5 ，不能选择在第2天买入，第3天卖出，这样就亏损7了；同时，你也不能在买入前卖出股票。

### 样例 2

**输入：**
```
[2,4,1]
```

**输出：**
```
2
```

### 样例 3

**输入：**
```
[3,2,1]
```

**输出：**
```
0
```', '', '["\u672a\u5206\u7c7b"]', '[]', '["Python", "C++", "Java"]', '{"Python": "def solve() -> None:\n    pass", "C++": "#include <bits/stdc++.h>\nusing namespace std;\n\nint main() {\n    return 0;\n}", "Java": "public class Main {\n    public static void main(String[] args) {\n    }\n}"}', '牛客', '牛客', '中', 2026, 'https://www.nowcoder.com/practice/64b4262d4e6d4f6181cd45446a5821ec?tpId=295&tqId=625&sourceUrl=%2Fexam%2Foj%3FquestionJobId%3D10%26subTabName%3Donline_coding_page', 'https://www.nowcoder.com/practice/64b4262d4e6d4f6181cd45446a5821ec?tpId=295&tqId=625&sourceUrl=%2Fexam%2Foj%3FquestionJobId%3D10%26subTabName%3Donline_coding_page', '未开始', '2026-07-03T18:02:14.890051+00:00', '2026-07-03T18:04:36.068851+00:00', 2000, 262144, '常见101', NULL, NULL) ON CONFLICT DO NOTHING;
