```
-1
```', '', '["\u672a\u5206\u7c7b"]', '[]', '["Python", "C++", "Java"]', '{"Python": "def solve() -> None:\n    pass", "C++": "#include <bits/stdc++.h>\nusing namespace std;\n\nint main() {\n    return 0;\n}", "Java": "public class Main {\n    public static void main(String[] args) {\n    }\n}"}', '牛客', '牛客', '中', 2026, 'https://www.nowcoder.com/practice/3911a20b3f8743058214ceaa099eeb45?tpId=295&tqId=988994&sourceUrl=%2Fexam%2Foj%3FquestionJobId%3D10%26subTabName%3Donline_coding_page', 'https://www.nowcoder.com/practice/3911a20b3f8743058214ceaa099eeb45?tpId=295&tqId=988994&sourceUrl=%2Fexam%2Foj%3FquestionJobId%3D10%26subTabName%3Donline_coding_page', '未开始', '2026-07-03T18:02:14.423130+00:00', '2026-07-03T18:06:27.947722+00:00', 2000, 262144, '常见101', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.problems VALUES (261, '矩阵的最小路径和', '矩阵的最小路径和', '牛客', 'Medium', 'dynamic-programming', '给定一个 n * m 的矩阵 a，从左上角开始每次只能向右或者向下走，最后到达右下角的位置，路径上所有的数字累加起来就是路径和，输出所有的路径中最小的路径和。 

